// Initial implementation
case class Deposit(amount: Double)
case class Withdraw(amount: Double)
case class GetBalance()

class AccountActor extends Actor {
  var balance: Double = 0.0
  
  def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! "Deposit successful"
      
